            this.CalcRcvInfo.Name = "CalcRcvInfo";
            // 
            // CalcRcvPhone
            // 
            this.CalcRcvPhone.DataMember = "WireSearchReceiptV1";
            this.CalcRcvPhone.Expression = "Iif([RcvCountry] == \'USA\', \r\n     Iif(not IsNullOrEmpty([RcvPhone]),\r\n           " +
    "Iif(Len([RcvPhone]) == 10, ToLong([RcvPhone]), ToLong(Substring([RcvPhone],1  ,1" +
    "0 ))) ,\'\')\r\n,[RcvPhone])";
            this.CalcRcvPhone.Name = "CalcRcvPhone";
            // 
            // CalcAgInfo
            // 
            this.CalcAgInfo.DataMember = "WireSearchReceiptV1";
            this.CalcAgInfo.Expression = resources.GetString("CalcAgInfo.Expression");
            this.CalcAgInfo.Name = "CalcAgInfo";
