            this.Teledirect.Description = "AgTeledirect";
            this.Teledirect.Name = "Teledirect";
            this.Teledirect.Type = typeof(bool);
            this.Teledirect.ValueInfo = "True";
            this.Teledirect.Visible = false;
            // 
            // CalcPhoneNoVerify
            // 
            this.CalcPhoneNoVerify.DataMember = "WireSearchReceiptV1";
            this.CalcPhoneNoVerify.Expression = "Iif([Parameters.CallerIDVerif] == False, \'Tel. no verificado. Phone not verified." +
    "\', \' \')";
            this.CalcPhoneNoVerify.Name = "CalcPhoneNoVerify";
            // 
            // CalcVerify
            // 
            this.CalcVerify.DataMember = "WireSearchReceiptV1";
            this.CalcVerify.Expression = "Iif([Parameters.CallerIDVerif] == False, \'VERIFICAR/VERIFY\', \' \')";
            this.CalcVerify.Name = "CalcVerify";
            // 
            // CalcNoFaxBaxInfo
            // 
            this.CalcNoFaxBaxInfo.DataMember = "WireSearchReceiptV1";
            this.CalcNoFaxBaxInfo.Expression = "Iif(IsNullOrEmpty([NoFaxBackWaitTime]),\'0\', [NoFaxBackWaitTime]) + \'Min\'";
            this.CalcNoFaxBaxInfo.Name = "CalcNoFaxBaxInfo";
            // 
            // CalcNoFaxBackInfoMsg
            // 
            this.CalcNoFaxBackInfoMsg.DataMember = "WireSearchReceiptV1";
            this.CalcNoFaxBackInfoMsg.Expression = " \' Para hacer cambios/ To make changes\'";
            this.CalcNoFaxBackInfoMsg.Name = "CalcNoFaxBackInfoMsg";
            // 
            // CalcChargeLabel
            // 
            this.CalcChargeLabel.DataMember = "WireSearchReceiptV1";
            this.CalcChargeLabel.Expression = "\'Cargos/Transf. Fees\' + \nIif([SenderPaymentMethodId] == 1, \n\'- w Cash\', Iif([Send" +
    "erPaymentMethodId] == 5, \'- w Deb. Card\', \'\'))";
            this.CalcChargeLabel.Name = "CalcChargeLabel";
            // 
            // CalcInstructionLabel
            // 
            this.CalcInstructionLabel.DataMember = "WireSearchReceiptV1";
            this.CalcInstructionLabel.Expression = "Iif([TransactionTypeEnglish] == \'DEPOSIT\', Char(13)\n,\'Instrucciones de Cobro/\' + " +
    "Char(13) + \'Payment Instructions\')";
            this.CalcInstructionLabel.Name = "CalcInstructionLabel";
